1	interface PolicyItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	const ITEM_PREMIUMS: Record<string, number> = {
9	  Sword: 100,
10	  Amulet: 60,
11	  Staff: 80,
12	  Potion: 40,
13	  Rune: 25,
14	  Moonstone: 25,
15	};
16	
17	const COMPONENT_TYPES = ["Rune", "Moonstone"];
18	
19	const PROCESSING_FEE = 5;
20	const DEFAULT_PREMIUM = 100;
21	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
22	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	
25	const applyItemSurcharges = (item: PolicyItem): number => {
26	  if (!(item.type in ITEM_PREMIUMS)) {
27	    throw new Error(`Unknown item type: ${item.type}`);
28	  }
29	  const basePremium = ITEM_PREMIUMS[item.type];
30	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
31	  const enchantmentMultiplier = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
32	    ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER
33	    : 1;
34	  return basePremium * cursedMultiplier * enchantmentMultiplier;
35	};
