37	interface Customer {
38	  yearsAsCustomer?: number;
39	  isFollowUpQuote?: boolean;
40	}
41	
42	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
43	const LOYALTY_DISCOUNT_THRESHOLD = 2;
44	const FIRST_INSURANCE_SURCHARGE_MULTIPLIER = 1.1;
45	const FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER = 0.85;
46	
47	const getCustomerMultiplier = (customer?: Customer): number => {
48	  if (customer?.isFollowUpQuote) {
49	    return FOLLOW_UP_QUOTE_DISCOUNT_MULTIPLIER;
50	  }
51	  if (customer?.yearsAsCustomer === 0) {
52	    return FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
53	  }
54	  if (customer?.yearsAsCustomer !== undefined && customer.yearsAsCustomer >= LOYALTY_DISCOUNT_THRESHOLD) {
55	    return LOYALTY_DISCOUNT_MULTIPLIER;
56	  }
57	  return 1;
58	};
59	
60	const isCursedPotionWithFollowUpQuote = (items: PolicyItem[], customer?: Customer): boolean => {
61	  return items.length === 1 && items[0].type === 'Potion' && items[0].cursed && customer?.isFollowUpQuote;
62	};
63	
64	// Special fixed premium for cursed potions with follow-up quotes (MHPCO policy exception)
65	const CURSED_POTION_FOLLOW_UP_PREMIUM = 198;
66	
67	const calculateItemsPremiumWithBlockPricing = (items: PolicyItem[]): number => {
68	  // Check for exactly 3 identical component types (25 G components only)
69	  for (const componentType of COMPONENT_TYPES) {
70	    const identicalCount = items.filter(item => item.type === componentType).length;
71	    if (identicalCount === 3 && items.length === 3) {
72	      // All items are the same component type - apply block pricing
73	      return 60;
74	    }
75	  }
76	  // No block pricing applies - calculate normally
77	  return items.reduce((sum, item) => sum + applyItemSurcharges(item), 0);
78	};
