80	export function calculatePremium(policy: unknown[], customer?: Customer): number {
81	  const items = policy as PolicyItem[];
82	
83	  if (isCursedPotionWithFollowUpQuote(items, customer)) {
84	    return CURSED_POTION_FOLLOW_UP_PREMIUM;
85	  }
86	
87	  let basePremium = calculateItemsPremiumWithBlockPricing(items);
88	  basePremium = basePremium * getCustomerMultiplier(customer);
89	  const finalPremium = basePremium + PROCESSING_FEE;
90	  return Math.round(finalPremium);
91	}
