93	const DEDUCTIBLE_PER_EVENT = 100;
94	const DRAGON_SWORD_ITEM_TYPE = "DragonSword";
95	const ENCHANTMENT_DAMAGE_REDUCTION_THRESHOLD = 8;
96	const ENCHANTMENT_DAMAGE_REDUCTION_FACTOR = 0.5;
97	
98	const isDragonMaterialItem = (items: PolicyItem[]): boolean => {
99	  return items.length > 0 && items[0].type === DRAGON_SWORD_ITEM_TYPE;
100	};
