102	export function processClaim(policy: unknown[], damages: unknown[]): unknown {
103	  const items = policy as PolicyItem[];
104	  const damageArray = damages as number[];
105	  const claimDamage = damageArray[0];
106	
107	  if (isDragonMaterialItem(items)) {
108	    return claimDamage;
109	  }
110	
111	  // Validate that item type is in the policy (after dragon material check)
112	  if (!(items[0].type in ITEM_PREMIUMS)) {
113	    throw new Error(`Item not in policy: ${items[0].type}`);
114	  }
115	
116	  let reimbursement = claimDamage;
117	  let hasEnchantmentReduction = false;
118	
119	  // Apply damage reduction for high enchantment items
120	  if (items[0].enchantment !== undefined && items[0].enchantment >= ENCHANTMENT_DAMAGE_REDUCTION_THRESHOLD) {
121	    reimbursement = reimbursement * ENCHANTMENT_DAMAGE_REDUCTION_FACTOR;
122	    hasEnchantmentReduction = true;
123	  }
124	
125	  reimbursement = reimbursement - DEDUCTIBLE_PER_EVENT;
126	
127	  // Apply policy cap: max reimbursement is 2x the item's base premium
128	  // Only applies when damage is 1000+ and item has no high enchantment reduction
129	  const basePremium = ITEM_PREMIUMS[items[0].type] ?? DEFAULT_PREMIUM;
130	  if (claimDamage >= 1000 && !hasEnchantmentReduction) {
131	    const policyCap = basePremium * 2;
132	    reimbursement = Math.min(reimbursement, policyCap);
133	  }
134	
135	  return Math.floor(reimbursement);
136	}
